mapper.select:
SELECT * FROM dashboard_stats
WHERE stat_date = #{statDate} AND stat_type = #{statType}
LIMIT 1

SELECT * FROM dashboard_trend
WHERE stat_date >= #{startDate}
ORDER BY stat_date ASC

SELECT * FROM dashboard_platform_stats
WHERE stat_date BETWEEN #{startDate} AND #{endDate}
AND stat_type = #{statType}
ORDER BY total_count DESC

SELECT * FROM dashboard_region_stats
WHERE stat_date BETWEEN #{startDate} AND #{endDate}
AND stat_type = #{statType}
ORDER BY news_count DESC

SELECT * FROM dashboard_hot_words
WHERE stat_date = #{statDate}
AND stat_type = #{statType}
AND word_type = #{wordType}
ORDER BY word_count DESC
LIMIT #{limit}

SELECT CONCAT(title, ' ', COALESCE(LEFT(content, 500), ''))
FROM news_data
WHERE DATE(create_time) = #{today}
  AND (title IS NOT NULL AND title != '')
ORDER BY create_time DESC
LIMIT #{limit}

SELECT COUNT(1) FROM news_data
WHERE DATE(create_time) = #{today}
AND (article_type != 'video' OR article_type IS NULL)

SELECT COUNT(1) FROM news_data
WHERE DATE(create_time) = #{today}
AND alert_id IS NOT NULL AND alert_id != 0

SELECT COUNT(1) FROM news_data
WHERE DATE(create_time) = #{yesterday}
AND alert_id IS NOT NULL AND alert_id != 0

SELECT COUNT(1) FROM news_data n
JOIN special_alert_setting s ON n.alert_id = s.alert_id
WHERE DATE(n.create_time) = #{today}
AND s.alert_level = #{level}
